  ('disabled-10ced7e2-moex-00003', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-114-4dccc0e6', 'sub-disabled-10ced7e2-01', NULL, 'single_choice', '政府組織是公共服務的主要提供者，此種獨占的特質容易導致行政無效率 與服務品質低落。下列何者不是用以解決此問題的方法？', '["設計多核心的治理結構，讓公民可以用腳投票，選擇服務較好的政府", "擴大政府職能範圍與預算規模", "將政府部門的服務以委託外包的方式處理", "政府資訊透明，讓民眾有機會監督官僚行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:49+00:00", "source_pdf_sha1": "143d18a0765f", "answer_pdf_sha1": "6681fcfa4b9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "402", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
